code.Java:
import java.util.*;

class Codechef {

    static long[] dp = new long[100005];

    static long fib(int n) {
        if (n == 1) return 0;
        if (n == 2) return 1;

        if (dp[n] != -1) return dp[n];

        return dp[n] = fib(n - 1) + fib(n - 2);
    }

    public static void main(String[] args) {
        Arrays.fill(dp, -1);

        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();

        System.out.println(fib(n));
    }
}
